package com.datamaster.module.assets.controller.admin.assetchild.files;import cn.hutool.core.date.DateUtil;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import com.datamaster.common.annotation.Log;import com.datamaster.common.core.controller.BaseController;import com.datamaster.common.core.domain.AjaxResult;import com.datamaster.common.core.domain.CommonResult;import com.datamaster.common.core.page.PageParam;import com.datamaster.common.core.page.PageResult;import com.datamaster.common.enums.BusinessType;import com.datamaster.common.utils.object.BeanUtils;import com.datamaster.common.utils.poi.ExcelUtil;import com.datamaster.module.assets.controller.admin.assetchild.files.vo.AssetsAssetFilesPageReqVO;import com.datamaster.module.assets.controller.admin.assetchild.files.vo.AssetsAssetFilesRespVO;import com.datamaster.module.assets.controller.admin.assetchild.files.vo.AssetsAssetFilesSaveReqVO;import com.datamaster.module.assets.convert.assetchild.files.AssetsAssetFilesConvert;import com.datamaster.module.assets.dal.dataobject.assetchild.files.AssetsAssetFilesDO;import com.datamaster.module.assets.service.assetchild.files.IAssetsAssetFilesService;import javax.annotation.Resource;import javax.servlet.http.HttpServletResponse;import javax.validation.Valid;import java.util.Arrays;import java.util.List;/** * 数据资产-文件服务Controller * * @author DATAMASTER * @date 2025-06-26 */@Tag(name = "数据资产-文件服务")@RestController@RequestMapping("/ast/assetFiles")@Validated
public class AssetsAssetFilesController extends BaseController {    @Resource    private IAssetsAssetFilesService AssetsAssetFilesService;    @Operation(summary = "查询数据资产-文件服务列表")    @PreAuthorize("@ss.hasPermi('da:assetFiles:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsAssetFilesRespVO>> list(AssetsAssetFilesPageReqVO AssetsAssetFiles) {        PageResult<AssetsAssetFilesDO> page = AssetsAssetFilesService.getDaAssetFilesPage(AssetsAssetFiles);        return CommonResult.success(BeanUtils.toBean(page, AssetsAssetFilesRespVO.class));    }    @Operation(summary = "导出数据资产-文件服务列表")    @PreAuthorize("@ss.hasPermi('da:assetFiles:export')")    @Log(title = "数据资产-文件服务", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsAssetFilesPageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsAssetFilesDO> list = (List<AssetsAssetFilesDO>) AssetsAssetFilesService.getDaAssetFilesPage(exportReqVO).getRows();        ExcelUtil<AssetsAssetFilesRespVO> util = new ExcelUtil<>(AssetsAssetFilesRespVO.class);        util.exportExcel(response, AssetsAssetFilesConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入数据资产-文件服务列表")    @PreAuthorize("@ss.hasPermi('da:assetFiles:import')")    @Log(title = "数据资产-文件服务", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsAssetFilesRespVO> util = new ExcelUtil<>(AssetsAssetFilesRespVO.class);        List<AssetsAssetFilesRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsAssetFilesService.importDaAssetFiles(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取数据资产-文件服务详细信息")    @PreAuthorize("@ss.hasPermi('da:assetFiles:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsAssetFilesRespVO> getInfo(@PathVariable("id") Long id) {        AssetsAssetFilesDO AssetsAssetFilesDO = AssetsAssetFilesService.getDaAssetFilesById(id);        return CommonResult.success(BeanUtils.toBean(AssetsAssetFilesDO, AssetsAssetFilesRespVO.class));    }    @Operation(summary = "新增数据资产-文件服务")    @PreAuthorize("@ss.hasPermi('da:assetFiles:add')")    @Log(title = "数据资产-文件服务", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsAssetFilesSaveReqVO AssetsAssetFiles) {        AssetsAssetFiles.setCreatorId(getUserId());        AssetsAssetFiles.setCreateBy(getNickName());        AssetsAssetFiles.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetFilesService.createDaAssetFiles(AssetsAssetFiles));    }    @Operation(summary = "修改数据资产-文件服务")    @PreAuthorize("@ss.hasPermi('da:assetFiles:edit')")    @Log(title = "数据资产-文件服务", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsAssetFilesSaveReqVO AssetsAssetFiles) {        AssetsAssetFiles.setUpdatorId(getUserId());        AssetsAssetFiles.setUpdateBy(getNickName());        AssetsAssetFiles.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetFilesService.updateDaAssetFiles(AssetsAssetFiles));    }    @Operation(summary = "删除数据资产-文件服务")    @PreAuthorize("@ss.hasPermi('da:assetFiles:remove')")    @Log(title = "数据资产-文件服务", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsAssetFilesService.removeDaAssetFiles(Arrays.asList(ids)));    }}